INSERT INTO `main_activity` VALUES (1,'post',NULL,'Enhance Your Workflow with Essential Browser Shortcuts\r\n\r\nMaximize efficiency and streamline your daily tasks with these practical browser productivity tips. From quick tab recovery to direct navigation and time management, these shortcuts are designed to support a faster, smarter work experience.\r\n\r\n#ProductivityTools #WorkplaceEfficiency #BrowserShortcuts #ProfessionalTips',NULL,'2025-06-23 05:15:25','2025-06-23 05:15:44',322,322,0),(2,'post',NULL,'If you’re looking for a simple and effective way to manage your daily workload, the 1–3–5 Rule might be just what you need. This productivity method encourages you to focus on one big task, three medium tasks and five small tasks each day. By structuring your to-do list this way, you can prioritize your most important work while still making progress on smaller items that keep momentum going.',NULL,'2025-06-23 12:27:28','2025-06-23 12:27:28',322,322,1),(3,'post',NULL,'Happy Birthday - Anushri Mishra',NULL,'2025-06-23 12:29:43','2025-06-23 12:29:43',322,322,1),(4,'post',NULL,'India–France AI Summit 2025 marks a pivotal step in global AI collaboration! From joint R&D in healthcare, agriculture and climate tech to empowering startups, fostering academic exchange and promoting ethical AI—this summit sets the stage for responsible innovation and a smarter future.',NULL,'2025-06-27 07:35:58','2025-06-27 07:35:58',322,322,1),(5,'post',NULL,'2nd Year Work Anniversary Wishes',NULL,'2025-06-30 13:20:48','2025-06-30 13:20:48',322,322,1),(6,'post',NULL,'2nd Year Work Anniversary Wishes - Bhuvaneswari K',NULL,'2025-06-30 13:21:24','2025-06-30 13:21:24',322,322,1),(7,'post',NULL,'1st Year Work Anniversary Wishes - Kirankumar Daga',NULL,'2025-06-30 13:21:59','2025-06-30 13:21:59',322,322,1),(8,'post',NULL,'Happy Birthday - Karthikeyan V',NULL,'2025-06-30 13:24:05','2025-06-30 13:24:05',322,322,1),(9,'post',NULL,'Happy Birthday - Dhanapal SP',NULL,'2025-07-01 03:21:33','2025-07-01 03:21:33',322,322,1),(10,'post',NULL,'Happy Birthday - Prasanna Kumar',NULL,'2025-07-02 03:37:17','2025-07-02 03:37:17',322,322,1),(11,'post',NULL,'Optimize Your Productivity with the Eisenhower Matrix\r\n\r\nEffectively manage your time by categorizing tasks based on urgency and importance.\r\n\r\nThis proven method helps you:\r\n✔ Prioritize critical work\r\n✔ Plan strategically\r\n✔ Delegate efficiently\r\n✔ Eliminate distractions\r\n\r\nAdopt smarter task management for better focus and performance.',NULL,'2025-07-03 05:07:39','2025-07-03 05:07:39',322,322,1),(12,'post',NULL,'Happy Birthday - Vimal S',NULL,'2025-07-03 06:02:45','2025-07-03 06:02:45',322,322,1),(13,'post',NULL,'Happy Birthday - Gokulakrishnan K',NULL,'2025-07-10 12:13:00','2025-07-10 12:13:00',322,322,1),(14,'post',NULL,'Congratulations - Rahini Raju',NULL,'2025-07-10 12:14:42','2025-07-10 12:14:42',322,322,1),(15,'post',NULL,'Congratulations - Manimala A',NULL,'2025-07-10 12:15:19','2025-07-10 12:15:19',322,322,1),(16,'post',NULL,'Condratulations - Vijayalakshmi Sekar',NULL,'2025-07-10 12:15:51','2025-07-11 12:01:40',322,322,0),(17,'post',NULL,'Congratulations - Swathi B',NULL,'2025-07-10 12:18:28','2025-07-10 12:18:28',322,322,1),(18,'post',NULL,'Happy Birthday - Sri Harsha Mutta',NULL,'2025-07-11 05:38:37','2025-07-11 05:38:37',322,322,1),(19,'post',NULL,'3rd Year Work Anniversary Wishes - Mandalaeswaran M',NULL,'2025-07-11 05:41:05','2025-07-11 05:41:05',322,322,1),(20,'post',NULL,'1st Year Work Anniversary Wishes - Jeevasurya L',NULL,'2025-07-11 05:44:25','2025-07-11 05:44:25',322,322,1),(21,'post',NULL,'2nd Year Work Anniversary Wishes - Ragini S',NULL,'2025-07-11 05:46:30','2025-07-11 05:46:30',322,322,1),(22,'post',NULL,'2nd Year Work Anniversary Wishes - Sabash Joseph Walls',NULL,'2025-07-11 05:47:33','2025-07-11 05:47:33',322,322,1),(23,'post',NULL,'Happy Birthday - Vishnu Priya K',NULL,'2025-07-15 04:28:42','2025-07-15 04:28:42',322,322,1),(24,'post',NULL,'Happy Birthday - Sumith R',NULL,'2025-07-15 04:30:51','2025-07-15 04:30:51',322,322,1),(25,'post',NULL,'Happy Birthday - Vijayaraj V',NULL,'2025-07-15 04:32:45','2025-07-15 04:32:45',322,322,1),(26,'post',NULL,'Work Anniversary Wishes - Manivel Ramu',NULL,'2025-07-15 04:34:02','2025-07-15 04:34:02',322,322,1),(27,'post',NULL,'Happy Birthday - Kavikkumar D',NULL,'2025-07-16 11:50:08','2025-07-16 11:50:08',322,322,1),(28,'post',NULL,'Happy Birthday -  Sathishkanna M',NULL,'2025-07-16 11:52:08','2025-07-16 11:52:08',322,322,1),(29,'post',NULL,'Work Anniversary Wishes - Gautham Prabakaran',NULL,'2025-07-16 11:52:47','2025-07-16 11:52:47',322,322,1),(30,'post',NULL,'Work Anniversary Wishes - Sabareeswaran G',NULL,'2025-07-17 04:47:04','2025-07-17 04:47:04',322,322,1),(31,'post',NULL,'We are proud to share a moment of national pride and inspiration—Group Captain Shubhanshu Shukla, a distinguished officer of the Indian Air Force, has made history as India’s first astronaut to board the International Space Station (ISS).\r\n\r\nMission Highlights:\r\n\r\nLaunch: June 25, 2025 (Axiom Mission-4 aboard SpaceX Dragon \"Grace\")\r\n\r\nDocked at ISS: June 26, 2025\r\n\r\nReturned: July 15, 2025\r\n\r\nDuration in Space: 18 days\r\n\r\nScientific Contributions:\r\nDuring his time aboard the ISS, Shukla conducted 60+ experiments in collaboration with ISRO, focusing on:\r\n\r\nSeed growth in space (moong, methi)\r\n\r\nBrain–computer interface technology\r\n\r\nMicrogravity effects on muscles, water dynamics, and more\r\n\r\nCyanobacteria-based oxygen generation research\r\n\r\nThis mission marks a giant leap in India\'s human spaceflight program, laying critical groundwork for Gaganyaan—India’s upcoming independent crewed mission.\r\n\r\nLet’s take a moment to celebrate this inspiring milestone in Indian space exploration. Shubhanshu Shukla\'s achievement reminds us of what’s possible through dedication, collaboration and vision.',NULL,'2025-07-17 10:31:05','2025-07-17 10:31:05',322,322,1),(32,'post',NULL,'Belated Birthday Wishes - Santhosh Raj',NULL,'2025-07-21 10:53:38','2025-07-21 10:53:38',322,322,1),(33,'post',NULL,'Happy Birthday - Rahini Raju',NULL,'2025-07-21 10:54:18','2025-07-21 10:54:18',322,322,1),(34,'post',NULL,'Paper Peak Challenge',NULL,'2025-07-24 05:48:38','2025-07-24 05:48:38',322,322,1),(35,'post',NULL,'Hello Team,\r\n\r\nWe’re excited to announce the Friday Fizz points earned during this week’s fun and engaging activities! Your participation, energy and enthusiasm truly made the event a success.',NULL,'2025-07-28 05:53:38','2025-07-28 05:53:38',322,322,1),(36,'post',NULL,'Work Anniversary Wishes: Aswin GT',NULL,'2025-07-30 03:23:14','2025-07-30 03:23:14',322,322,1),(37,'post',NULL,'Work Anniversary Wishes:  Udayasankar A',NULL,'2025-07-30 03:23:41','2025-07-30 03:23:41',322,322,1),(38,'post',NULL,'Welcome to the Family - Jegan K',NULL,'2025-07-30 03:25:47','2025-07-30 03:25:47',322,322,1),(39,'post',NULL,'Welcome to the Family  - Keerthiraj K',NULL,'2025-07-30 03:26:27','2025-07-30 03:26:27',322,322,1),(40,'post',NULL,'Welcome to the Family - Sasikumar P',NULL,'2025-07-30 03:28:30','2025-07-30 03:28:30',322,322,1),(41,'article','POSH (Prevention of Sexual Harassment) training session','<p>Dear Team,</p><p>&nbsp;</p><p>This is to inform you that a POSH (Prevention of Sexual Harassment) training session has been scheduled for tomorrow, 30th July 2025, at 2:00 PM.</p><p>The training is part of our ongoing efforts to create a safe, respectful and inclusive workplace for everyone. It is essential for all employees to understand the guidelines, policies and preventive measures related to sexual harassment at the workplace.</p><p>&nbsp;</p><h3>Training Details:</h3><ul><li>Date: 30th July 2025 (Wednesday)</li><li>Time: 2:00 PM to 3:00 PM</li><li>Mode: In-person</li><li>Venue: 2nd Floor New Bay</li></ul><p>Employees who are currently stationed at client locations or are working remotely may attend the session virtually. A meeting link will be shared prior to the session.</p><p>&nbsp;</p><h3>Important Note:</h3><ul><li>Attendance is mandatory for all employees, irrespective of role or location.</li><li>Please ensure you are available and prepared to join the session on time.</li><li>Managers are requested to encourage their team members to participate without fail.</li></ul><p>This training is a compliance requirement and also a step towards building a culture of dignity, awareness and accountability in the workplace. Your active participation and attention during the session will be highly appreciated.</p><p>&nbsp;</p><p>For any queries or concerns regarding the session or participation, feel free to reach out to the HR team.</p><p>&nbsp;</p><p>Thank you for your cooperation.</p><p>&nbsp;</p><p><strong>Regards,</strong></p><p><strong>HR Department</strong></p>',NULL,'2025-07-30 03:40:56','2025-07-30 03:40:56',322,322,1),(42,'post',NULL,'Work Anniversary Wishes: Jobin Raj',NULL,'2025-07-30 04:28:46','2025-07-30 04:28:46',322,322,1),(43,'post',NULL,'UPI Rules Changing',NULL,'2025-07-31 16:07:45','2025-07-31 16:07:45',322,322,1),(44,'post',NULL,'Happy Birthday - Mohamed Ashraf M',NULL,'2025-08-04 05:09:39','2025-08-04 05:09:39',322,322,1),(45,'post',NULL,'Work Anniversary Wishes - Santhosh Raj N',NULL,'2025-08-04 05:10:28','2025-08-04 05:10:28',322,322,1),(46,'post',NULL,'Happy Birthday - Pranav P',NULL,'2025-08-05 03:44:00','2025-08-05 03:44:00',322,322,1),(47,'post',NULL,'Congratulations Balu Devan J',NULL,'2025-08-06 03:17:18','2025-08-06 03:17:18',322,322,1),(48,'post',NULL,'Happy Birthday - Bhuvaneswari K',NULL,'2025-08-06 03:23:55','2025-08-06 03:23:55',322,322,1),(49,'post',NULL,'Happy Birthday - Anandan V',NULL,'2025-08-07 03:27:29','2025-08-07 03:27:29',322,322,1),(50,'post',NULL,'Work Anniversary Wishes - Nisha R',NULL,'2025-08-07 03:28:29','2025-08-07 03:28:29',322,322,1),(51,'post',NULL,'Happy Birthday - KIRUTHIKA R S',NULL,'2025-08-08 04:17:00','2025-08-08 04:17:00',322,322,1),(52,'post',NULL,'Happy Birt